## Code Example
```swift
import UIKit

actor ImageLoader {
    private let memCache = NSCache<NSString, UIImage>()
    private let fileManager = FileManager.default
    private let diskDir: URL

    init(diskFolder: URL) { self.diskDir = diskFolder }

    func load(from url: URL) async -> UIImage? {
        let key = url.absoluteString as NSString
        if let image = memCache.object(forKey: key) { return image }
        let path = diskDir.appendingPathComponent(url.lastPathComponent)
        if let data = try? Data(contentsOf: path), let image = UIImage(data: data) {
            memCache.setObject(image, forKey: key)
            return image
        }
        guard let (data, _) = try? await URLSession.shared.data(from: url),
              let image = UIImage(data: data) else { return nil }
        memCache.setObject(image, forKey: key)
        try? data.write(to: path)
        return image
    }
}
```

