## Code Example

```javascript
// Swift-like pseudocode: apply a patch to a Comment
func apply(patch: Patch, to comment: inout Comment) {
    // Validate base version matches current state
    guard patch.baseVersion == comment.version else {
        // Handle conflict resolution
        resolveConflict(patch: patch, comment: &comment)
        return
    }

    // Apply delta changes
    for change in patch.changes {
        switch change.type {
        case .insert:
            comment.text.insert(change.text, at: change.position)
        case .delete:
            comment.text.removeSubrange(change.range)
        case .replace:
            comment.text.replaceSubrange(change.range, with: change.text)
        }
    }

    // Update version and timestamps
    comment.version += 1
    comment.updatedAt = Date()
}
```

