// Skeleton: Filter protocol and graph actor
actor FilterGraph {
  struct Node { var id: String; var filter: CIFilter }
  var nodes: [Node] = []
  func applyAll(base: CIImage) async -> CIImage {
    var current = base
    for n in nodes {
      n.filter.setValue(current, forKey: kCIInputImageKey)
      if let out = n.filter.outputImage {
        current = out
      }
    }
    return current
  }
}
