  @Published var remaining: Int = 0
  @Published var isRunning: Bool = false
  private var cancellable: AnyCancellable?
  func start(duration: Int) {
    remaining = duration * 60
    isRunning = true
    cancellable = Timer.publish(every: 1, on: .main, in: .common)
      .autoconnect()
      .sink { [weak self] _ in
