        validateField(fieldId)
        updateFieldVisibility()
        saveOffline()
    }

    private func validateField(_ fieldId: String) {
        guard let field = schema.fields.first(where: { $0.id == fieldId }),
              let validation = field.validation else {
            validationErrors.removeValue(forKey: fieldId)
            return
        }

        let value = formState[fieldId]
        var errors: [String] = []

        if validation.required == true && (value == nil || value as? String == "") {
            errors.append("This field is required")
        }

        if let stringValue = value as? String {
            if let minLength = validation.minLength, stringValue.count < minLength {
                errors.append("Minimum length is \(minLength) characters")
            }

            if let maxLength = validation.maxLength, stringValue.count > maxLength {
                errors.append("Maximum length is \(maxLength) characters")
            }

            if let pattern = validation.pattern {
                let regex = try? NSRegularExpression(pattern: pattern)
                let range = NSRange(location: 0, length: stringValue.utf16.count)
                if regex?.firstMatch(in: stringValue, options: [], range: range) == nil {
                    errors.append("Invalid format")
                }
            }
        }

        validationErrors[fieldId] = errors.isEmpty ? nil : errors.first
    }

    private func updateFieldVisibility() {
        var newVisibleFields = Set<String>()

        for field in schema.fields {
            if let visibility = field.visibility {
                if shouldShowField(field: field, rules: visibility) {
                    newVisibleFields.insert(field.id)
                }
            } else {
                newVisibleFields.insert(field.id)
            }
        }

        visibleFields = newVisibleFields
    }

    private func shouldShowField(field: FieldDefinition, rules: VisibilityRules) -> Bool {
        guard let conditions = rules.conditions else { return true }

        for condition in conditions {
            let dependentValue = formState[condition.fieldId]
            let expectedValue = condition.value

            switch condition.operator {
            case .equals:
                if "\(dependentValue ?? "")" != "\(expectedValue)" {
                    return false
                }
            case .notEquals:
                if "\(dependentValue ?? "")" == "\(expectedValue)" {
                    return false
                }
            case .contains:
                if let stringValue = dependentValue as? String {
                    if !stringValue.contains(expectedValue) {
                        return false
                    }
                }
            }
        }

        return true
    }

    func submitForm() async throws {
        let submissionData = FormSubmission(
            id: UUID().uuidString,
            timestamp: Date(),
            formData: formState,
            schemaVersion: schema.version
        )

        try await networkManager.submitForm(submissionData)
        persistenceManager.markAsSubmitted(submissionData.id)
    }
}

class CoreDataManager {
    func saveOffline(_ data: FormSubmission) {
        let context = persistentContainer.viewContext
        let entity = FormSubmissionEntity(context: context)
        entity.id = data.id
        entity.timestamp = data.timestamp
        entity.formData = try? JSONEncoder().encode(data.formData)
        entity.isSubmitted = false

        try? context.save()
    }

    func getPendingSubmissions() -> [FormSubmission] {
        let context = persistentContainer.viewContext
        let request: NSFetchRequest<FormSubmissionEntity> = FormSubmissionEntity.fetchRequest()
        request.predicate = NSPredicate(format: "isSubmitted == false")

        return (try? context.fetch(request))?.compactMap { entity in
            guard let data = entity.formData,
                  let formData = try? JSONDecoder().decode([String: Any].self, from: data) else {
                return nil
            }

            return FormSubmission(
                id: entity.id ?? "",
                timestamp: entity.timestamp ?? Date(),
                formData: formData,
                schemaVersion: "1.0"
            )
        } ?? []
    }
}

class NetworkManager {
    func submitForm(_ data: FormSubmission) async throws {
        let url = URL(string: "https://api.example.com/forms")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue(data.id, forHTTPHeaderField: "X-Idempotency-Key")

        let jsonData = try JSONEncoder().encode(data)
        request.httpBody = jsonData

        try await executeWithRetry(request: request)
    }

    private func executeWithRetry(request: URLRequest, maxRetries: Int = 3) async throws {
        var delay: TimeInterval = 1.0

        for attempt in 0...maxRetries {
            do {
                let (_, response) = try await URLSession.shared.data(for: request)

                if let httpResponse = response as? HTTPURLResponse {
                    if httpResponse.statusCode == 200 || httpResponse.statusCode == 201 {
                        return
                    } else if httpResponse.statusCode == 409 {
                        return
                    } else if httpResponse.statusCode >= 500 {
                        throw NetworkError.serverError
                    } else {
                        throw NetworkError.clientError(httpResponse.statusCode)
                    }
                }
            } catch {
                if attempt == maxRetries {
                    throw error
                }

                try await Task.sleep(nanoseconds: UInt64(delay * 1_000_000_000))
                delay *= 2
            }
        }
    }
}
