struct Post { let id: String; var version: Int; var content: String }
struct Delta { let id: String; let version: Int; let content: String }

func merge(_ deltas: [Delta], into cache: inout [String: Post]) -> [Post] {
  for d in deltas {
    if var existing = cache[d.id] {
      if d.version > existing.version {
        existing.version = d.version
        existing.content = d.content
        cache[d.id] = existing
      }
    } else {
      cache[d.id] = Post(id: d.id, version: d.version, content: d.content)
    }
  }
  return Array(cache.values)
}
```

